                      byteenable[3:0]      :
                      {4{1'b0}};

assign  we_redund_2 = write & redund_2_sel ?
                      byteenable[3:0]      :
                      {4{1'b0}};

assign  we_redund_3 = write & redund_3_sel ?
                      byteenable[3:0]      : 
