    else if (we_redund_3[3]) // Write enable
      begin
        redund_3_ff[31:24] <= writedata[31:24] & RED_PARAM_3[31:24];
      end
    else // Keep value
      begin
        redund_3_ff[31:24] <= redund_3_ff[31:24] & RED_PARAM_3[31:24];
      end
  end // block: redund_3_31_24_register


